INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (7, 'R1', '2026-04-30', 'Alessandra Nunes', 'APROVADO', '76 pesquisas. Pequeno nervosismo no início, mas evoluiu bem.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (50, 'R1', '2026-04-30', 'Nazaré', 'APROVADO C/ OBS', '3 ressalvas: contradição rejeição/voto Senado, esquecimento de filtro de eleitor, repetição de candidato em rejeição.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (36, 'R1', '2026-04-30', 'Gian', 'AJUSTES IMPORTANTES', '17/20 com erro: incoerências múltiplas, esqueceu nomes, idade errada, bairro errado, entrevistou pessoa que não vota em Manacapuru.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (29, 'R1', '2026-04-30', 'Alessandra Rocha', 'AJUSTES SIMPLES', 'Múltiplas incoerências em Senado, perguntou sexo (proibido), citou opções nulo/branco (indução).', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (28, 'R1', '2026-04-30', 'Eliete', 'ADVERTÊNCIA FINAL', 'Auditor: NÃO TEM MATERIAL EM MÃOS. Indução massiva, terceiros respondendo, famílias com respostas idênticas em intervalos curtos.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (40, 'R1', '2026-04-30', 'Karina', 'ADVERTÊNCIA FINAL', '"Mario Fonseca" como bairro em ~30 pesquisas, mesmo entrevistado declarando outros. Citou nomes em todas. Idade errada.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (74, 'R1', '2026-04-30', 'Sara', 'AJUSTES IMPORTANTES', 'Não pergunta se vota no município, religião errada, números aleatórios em telefone, entrevistados fora de cotação.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (16, 'R1', '2026-04-30', 'Talitha', 'ADVERTÊNCIA FINAL', '67 pesquisas, todas com problema. Não pergunta filtros, telefones inventados, comentário sobre "decorar contato da moça".', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (58, 'R1', '2026-04-30', 'Alice', 'AJUSTES IMPORTANTES', '24+ sem perguntar se era eleitor. Suspeita de uso de cartela. Idade e religião erradas.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (22, 'R1', '2026-04-30', 'Allan', 'AJUSTES IMPORTANTES', '13 incoerências. ATENÇÃO: entrou na residência dos entrevistados; pediu para analfabeto ler.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (56, 'R1', '2026-04-30', 'Layane', 'AJUSTES SIMPLES', 'Erros sistemáticos de religião (cristão→católico). Cita opções (indução em todas).', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (23, 'R1', '2026-04-30', 'Camila + Ely', 'AJUSTES IMPORTANTES', 'Indução sistemática, números fictícios reutilizados. Auditado por DUAS auditoras.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (14, 'R1', '2026-04-30', 'Camila', 'APROVADO C/ OBS', 'Cita nome dos candidatos (indução leve), não confirma nome quando entrevistado aponta, 1 incoerência.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (30, 'R1', '2026-04-30', 'Alice', 'AUDITORIA PENDENTE', 'Aguardando complemento da auditoria — cobrar Alice.', FALSE);
INSERT INTO auditorias (pesquisador_id, rodada, data_auditoria, auditor, resultado, detalhes, mensagem_enviada) VALUES (75, 'R1', '2026-04-30', 'Alessandra Rocha', 'APROVADO C/ OBS', 'Ambiente barulhento e voz baixa demais. Orientar locais silenciosos e elevar volume.', FALSE);
